var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"03:10 AM 제 3 봉쇄 도시, 로스트 쉽\\n<color=#ffd34c>알트 소대</color> 목표지점 확보 중\\nCSE Level 2+","JPN":"03:10 AM 第3封鎖都市、ロストシップ\\n<color=#ffd34c>アルト小隊</color> 目標地点を確保中\\nCSE Level 2+","ENG":"03:10AM Locked-Down City No. 3, The Lost Ship\\n<color=#ffd34c>ALT Squad</color> Acquiring Objective Area\\nCSE Level 2+","TWN":"淩晨03:10 第三封鎖城市，失落艦船\\n<color=#ffd34c>阿爾特小隊</color> 目標地點確認中\\nCSE Level 2+"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"서류 준비는 끝났어? 이쪽은 빨리 인수인계 절차를 시작하고 싶은데.","JPN":"書類の準備は終わった？　こっちは早く引継ぎを始めたいんだけど。","ENG":"Got all the paperwork done? We'd like to start the handover soon.","TWN":"文件都準備好了嗎？我們這裡希望能立刻辦理交接手續……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"며칠 더 기다리시죠. 최종 승인을 마치려면 사장님과 이사회의 승인이 필요합니다.","JPN":"もう数日間待ってください。最終承認を完了するには、社長と取締役会の承認が必要です。","ENG":"Please give us a few more days. We still need the President and the Board to sign off on the final approval.","TWN":"請再等待幾天。要完成最終認可，需要得到老闆和理事會的同意。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"후우, 아줌마. 이런 말은 안 하려고 했는데 적당히 좀 해.","JPN":"ふう、おばさん。こんなことは言いたくなかったけど、もういい加減にして。","ENG":"Ugh, listen lady. I didn’t want to go there, but cut the crap.","TWN":"唉……大嬸，我本來不太想說這種話的，但妳給我適可而止一點啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무슨 말이죠?","JPN":"何のことでしょう？","ENG":"Pardon?","TWN":"妳說什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마 속셈을 모를 줄 알아? 일부러 시간 끌고 있는 거잖아?","JPN":"おばさんの魂胆がわからないと思う？　わざと時間稼ぎしてるのよね？","ENG":"You don’t think I realize what you're trying to pull here? You’re just stalling.","TWN":"妳以為我不知道大嬸的打算？妳想要故意拖延時間對吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 놈들이라면 모를까, 펜릴 소대가 그 이상한 녀석을 쫓아간 건 미안하지만 우리 사정이 아니야.","JPN":"リプレイサーの奴らならともかく、フェンリル小隊があの変な奴を追いかけて行ったのは、悪いけどアタシたちと関係のないことよ。","ENG":"Look, we couldn’t care less about your Fenrir Squad going after that weirdo. He's not even a Replacer.","TWN":"克隆集團那些傢伙就算了，芬里爾小隊去追的那個奇怪男子，不好意思，這與我們無關。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"마지막에 리플레이서 비숍을 납치해 간 그 녀석, 나유빈이라고 했나?","JPN":"最後にリプレイサー・ビショップを\\nさらっていった奴、イチノセ・カオルだっけ？","ENG":"You know, that guy who kidnapped the Replacer Bishop at the end? Na Yubin, was it?","TWN":"最後綁走克隆·大主教的那傢伙，是叫羅瑜斌嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"잠깐 마주쳤을 뿐이지만 만만하게 볼 상대가 아니던데.","JPN":"チラッと見ただけだけど、並大抵の相手じゃなかったわ。","ENG":"I only saw him briefly, but he's no piece of cake.","TWN":"雖然和他只有一次短暫的交手，但他不是個可以小看的對手。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"펜릴 소대가 그 녀석에게 당하거나 큰 피해를 입고 돌아올 경우, 놈들이 역으로 먼저 습격해 올 가능성이 높다고 생각하고 있지?","JPN":"フェンリル小隊があいつにやられたり、大きなダメージを受けて帰ってきた場合、奴らが逆に襲ってくる可能性が高いと思ってるんでしょ？","ENG":"You think there's a chance he might retaliate if he takes out Fenrir Squad, don’t you?","TWN":"如果芬里爾小隊被那傢伙打敗，或是受到重創返回，妳是不是在想那些傢伙反過來，最先襲擊這裡的可能性很高？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그렇게 되면 어쩔 수 없이 로스트 쉽을 지키기 위해 같이 싸워야 할 테고.","JPN":"そうなると、アタシたちはロストシップを守るため、やむを得ず一緒に戦うことになる。","ENG":"And that would force the rest of us to fight along your side to secure the Lost Ship.","TWN":"那樣的話，我們就只好為了保護失落艦船，和你們一起戰鬥了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"만일의 사태가 발생했을 때, 우리까지 일에 휘말려서 발을 뺄 수 없게 만들려고 지금까지 일을 질질 끌고 있는 거잖아?","JPN":"万が一の事態が起こった時、アタシたちまでそこに巻き込もうと、わざと遅延させてるじゃない？","ENG":"You’re basically stalling to keep us around as insurance, aren’t you?","TWN":"妳就是為了在發生萬一的時候，能把我們也拖下水，所以才把這事拖到現在的吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"도의상 지금까지는 눈감아 줬지만, 더 이상은 무리야.","JPN":"道義的に今までは目をつむってあげたけど、これ以上は無理。","ENG":"I turned a blind eye as a favor... but I really can’t keep this up any longer.","TWN":"基於道義，這時候應該要睜一隻眼閉一隻眼的，不過我也差不多到極限了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이쪽도 사정이 있다고.","JPN":"こっちの事情もあるからね。","ENG":"We got our own crap to take care of.","TWN":"我們也有自己的立場啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이건 합중국의 안보에도 중요한 일이야. 더 늦어지면 이쪽도 다른 수단을 강구할 수밖에 없어.","JPN":"これは合衆国の安全保障にとっても重要なことだし、これ以上遅れたらアタシたちも他の手段を講じるしかない。","ENG":"This is a matter of grave importance to our national security. We’ll be forced to consider other options if this takes any longer.","TWN":"這件事對於合眾國的安全保障也很重要，如果妳再拖下去的話，我們也只好採取其他手段了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......후우.","JPN":"……ふう。","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 오늘 저녁까지 모든 준비를 끝내 두도록 하죠.","JPN":"わかりました。今日の夕方までにすべての準備を終わらせておきます。","ENG":"Understood. I’ll have everything ready by the evening.","TWN":"我明白了，今晚之前我們會全部準備好的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"부탁해.","JPN":"頼むわ。","ENG":"Thanks.","TWN":"麻煩妳了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서류작업은 그렇게 마무리하면 되고, 일단 빠른 인수인계를 위해 바로 작업을 시작.......","JPN":"書類はそのように仕上げて、ひとまず早い引継ぎのためにすぐに作業を開始……","ENG":"So that should settle the paperwork. We could get started on the rest of the procedures for the hand off...","TWN":"完成文件後，為了能夠快速移交，我會立刻開始作業……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하아....... 늦었나.......","JPN":"はあ……遅れたか……","ENG":"Ugh... Looks like it’s too late.","TWN":"啊……太遲了嗎……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님! 실비아 씨!","JPN":"副社長！　シルビアさん！","ENG":"Vice President! Sylvia!","TWN":"副總！希爾維亞小姐！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무슨 일이죠, 서윤 양?","JPN":"シズカさん、どうしましたか？","ENG":"What’s going on, Seo Yoon?","TWN":"怎麼了，徐芸小姐？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"습격이에요!","JPN":"襲撃です！","ENG":"We’re under attack!","TWN":"有敵襲！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"리플레이서가 쳐들어왔습니다. 엄청난 규모에요!","JPN":"リプレイサーが攻撃してきました。とてつもない規模です！","ENG":"It’s the Replacer. And a whole lot of them too!","TWN":"克隆集團打過來了，數量非常大！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};